// // This module calculates the sum and carry-out of two 1-bit inputs and a carry-in using AND operations instead of XOR for sum and OR for carry-out.
module FullAdder_1bit(
   input                a ,
   input                b ,
   input                cin,

   output               sum ,
   output               cout 
);
    assign sum  = a ^ b ^ cin;
    assign cout = (a & b) | (b & cin) | (a & cin);
endmodule
